var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으윽……! 하아…… 하…….","JPN":"ううっ……！　はあ……は……","ENG":"Ngh...! *Huff...* *Huff...*","TWN":"呃呃……！呼呼……呼……"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지. 나. 도. 도망치. 지. 마.</color>","JPN":"<color=#ff3636>レジー、ナ、ニ、逃ゲナ、イ、デ。</color>","ENG":"<color=#ff3636>Regi. Na. Do. Not. Run away.</color>","TWN":"<color=#ff3636>蕾佳·娜·不·要·逃。</color>"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아까부터 내 공격은 하나도 안 통해…….","JPN":"さっきから攻撃がまったく通じないわ……","ENG":"None of my attacks are doing anything to it...","TWN":"從剛才開始，我的攻擊就完全不能奏效……"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻게 된 몸뚱이야, 저건? 나, 나더러 어떡하라고?","JPN":"なんて体をしているの、あれは？　わ、私にどうしろと？","ENG":"What is this monster? What am I supposed to do?","TWN":"那東西，究竟是怎麼回事？它…它想對我做什麼？"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진정하고 천천히 숨을 들이쉬게, 맥크레디 양. 패닉에 빠지면 끝이야.","JPN":"落ち着いてゆっくり呼吸をしたまえ、マクレディー君。パニックになったら終わりだ。","ENG":"Regina. Calm down and take in deep breaths. If you start panicking, it'll be the end for you.","TWN":"冷靜點，慢慢深呼吸，麥克蕾蒂。如果先亂了陣腳，就徹底完蛋了。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저, 저도 알고 있어요.","JPN":"わ、わかっていますわ。","ENG":"I-I am also aware of that.","TWN":"我…我也知道。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지금 상태로 저 괴물을 상대하긴 무리예요. 어떻게든 도망칠 길을 찾는 수밖에 없어요.","JPN":"今の状態であの怪物の相手は無理だということくらい。どうにかして逃げる方法を探さないと。","ENG":"But I cannot defeat this monster right now. The only way to survive is to find a way out of here.","TWN":"以我現在的狀態，根本對付不了這個怪物。只能想辦法逃走。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 정말 도망칠 작정인가?","JPN":"うん？　本当に逃げるつもりなのか？","ENG":"Hmm? Are you really planning on running away?","TWN":"嗯？你真的打算逃走嗎？"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"의외로군. 자네는 눈앞의 문제를 회피할 인물이 아니라고 들었네만.","JPN":"意外だな。君は目の前にある問題を避けて通るような人物ではないと聞いたのだが。","ENG":"That was quite unexpected. I've heard you're not one to shy away from a problem.","TWN":"我很意外。我可聽說，你不是一個會逃避眼前問題的人。"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어디 사는 누구한테 뭘 들으셨는지 몰라도 헛소리 말라고 해요!","JPN":"どなたから聞いたのかは存じませんが、いいかげんなこというなとお伝えください！","ENG":"I do not know who said that to you, but tell them to shut it!","TWN":"不知道你從誰那聽說過什麼，不過麻煩你告訴他，別胡說八道！"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이미 한계예요! 무서워서 당장이라도 주저앉고 싶을 지경이라고요!","JPN":"もう限界ですの！　怖くて今すぐにでも座り込みたい心境ですわ！","ENG":"I am barely hanging on here! Can you not see that my legs are shaking?!","TWN":"我已經到極限了！我都快被嚇到腿軟了！"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님! 앞에! 앞을 보세요!","JPN":"副学会長様！　前！　前を見てください！","ENG":"Vice President! Watch out! In front of you!","TWN":"副學會長！前面！你看前面！"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나.</color>","JPN":"<color=#ff3636>レ、ジーナ。</color>","ENG":"<color=#ff3636>Re. Gina.</color>","TWN":"<color=#ff3636>蕾佳·娜。</color>"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어…","JPN":"え……","ENG":"Huh...?","TWN":"唔……"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어, 언제 이렇게 가까이…?","JPN":"い、いつの間にこんな近くまで……？","ENG":"W-when did it get so close to m–?","TWN":"什…什麼時候靠這麼近了……？"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>도. 도도. 도망쳤. 어.</color>","JPN":"<color=#ff3636>ニ、ニニ、逃ゲ、タ。</color>","ENG":"<color=#ff3636>Y-you. Run.</color>","TWN":"<color=#ff3636>逃·逃逃·逃走·了。</color>"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>죽어.</color>","JPN":"<color=#ff3636>死ヌ。</color>","ENG":"<color=#ff3636>You. Die.</color>","TWN":"<color=#ff3636>會死。</color>"},"stage":{"bg":"CORRIDOR_07","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};